queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?steakhouses a :SteakHouses .
    ?steakhouses p:name ?name .
    ?steakhouses p:Year_of_establishment ?year_of_establishment_f .
    FILTER((STR(?year_of_establishment_f) = "1980" || STR(?year_of_establishment_f) = "1980.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?seafoodrestaurants a :SeaFoodRestaurants .
    ?seafoodrestaurants p:name ?name .
    ?seafoodrestaurants p:Year_of_establishment ?year_of_establishment_f .
    FILTER((STR(?year_of_establishment_f) = "1980" || STR(?year_of_establishment_f) = "1980.0"))
    BIND(?name AS ?o0)
  }
}

